import{_ as e,o as a,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"정리 및 Q&A","description":"","frontmatter":{},"headers":[],"relativePath":"part6-closing/index.md","filePath":"part6-closing/index.md"}'),l={name:"part6-closing/index.md"};function d(o,t,s,i,c,h){return a(),r("div",null,[...t[0]||(t[0]=[n(`<h1 id="정리-및-q-a" tabindex="-1">정리 및 Q&amp;A <a class="header-anchor" href="#정리-및-q-a" aria-label="Permalink to &quot;정리 및 Q&amp;A&quot;">​</a></h1><h2 id="_3세대-비교-—-한-장-요약" tabindex="-1">3세대 비교 — 한 장 요약 <a class="header-anchor" href="#_3세대-비교-—-한-장-요약" aria-label="Permalink to &quot;3세대 비교 — 한 장 요약&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:center;">1세대 프롬프트</th><th style="text-align:center;">2세대 컨텍스트</th><th style="text-align:center;">3세대 하네스</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>핵심 질문</strong></td><td style="text-align:center;">&quot;뭐라고 물어볼까?&quot;</td><td style="text-align:center;">&quot;뭘 알려줄까?&quot;</td><td style="text-align:center;">&quot;팀을 어떻게 꾸릴까?&quot;</td></tr><tr><td style="text-align:left;"><strong>작업 단위</strong></td><td style="text-align:center;">단일 프롬프트</td><td style="text-align:center;">프로젝트 전체</td><td style="text-align:center;">전문 에이전트 팀</td></tr><tr><td style="text-align:left;"><strong>저장</strong></td><td style="text-align:center;">없음</td><td style="text-align:center;">파일 (md, json)</td><td style="text-align:center;"><code>.agents/</code> 전체</td></tr><tr><td style="text-align:left;"><strong>비유</strong></td><td style="text-align:center;">프리랜서에게 잘 설명</td><td style="text-align:center;">프리랜서에게 매뉴얼 제공</td><td style="text-align:center;">전문 팀 구성</td></tr><tr><td style="text-align:left;"><strong>확장성</strong></td><td style="text-align:center;">❌</td><td style="text-align:center;">△</td><td style="text-align:center;">⭐</td></tr><tr><td style="text-align:left;"><strong>재현성</strong></td><td style="text-align:center;">❌</td><td style="text-align:center;">△</td><td style="text-align:center;">⭐</td></tr><tr><td style="text-align:left;"><strong>토큰 효율</strong></td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">⭐</td></tr><tr><td style="text-align:left;"><strong>품질 보증</strong></td><td style="text-align:center;">❌</td><td style="text-align:center;">△</td><td style="text-align:center;">⭐</td></tr><tr><td style="text-align:left;"><strong>멀티 벤더</strong></td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">⭐</td></tr></tbody></table><h2 id="오늘-배운-것" tabindex="-1">오늘 배운 것 <a class="header-anchor" href="#오늘-배운-것" aria-label="Permalink to &quot;오늘 배운 것&quot;">​</a></h2><h3 id="이론" tabindex="-1">이론 <a class="header-anchor" href="#이론" aria-label="Permalink to &quot;이론&quot;">​</a></h3><ol><li><strong>바이브 코딩</strong>은 자연어로 AI에게 코딩을 시키는 패러다임</li><li><strong>프롬프트 엔지니어링</strong> → <strong>컨텍스트 엔지니어링</strong> → <strong>하네스 엔지니어링</strong>의 3세대 진화</li><li>하네스 엔지니어링 = 여러 전문 AI 에이전트를 역할 기반으로 협업시키는 기술</li></ol><h3 id="실습" tabindex="-1">실습 <a class="header-anchor" href="#실습" aria-label="Permalink to &quot;실습&quot;">​</a></h3><ol start="4"><li><strong>oh-my-agent</strong> = 포터블 멀티 에이전트 하네스 (한 줄 설치)</li><li><code>/brainstorm</code> → 아이디어를 구체화하고 설계 문서 생성</li><li><code>/plan</code> → PM이 태스크로 분해하고 실행 계획 수립</li><li><code>/orchestrate</code> → 에이전트들이 병렬로 자동 실행</li></ol><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><h3 id="더-알아보기" tabindex="-1">더 알아보기 <a class="header-anchor" href="#더-알아보기" aria-label="Permalink to &quot;더 알아보기&quot;">​</a></h3><table tabindex="0"><thead><tr><th>리소스</th><th>링크</th></tr></thead><tbody><tr><td>📖 oh-my-agent 공식 문서</td><td><a href="https://first-fluke.github.io/oh-my-agent/" target="_blank" rel="noreferrer">first-fluke.github.io/oh-my-agent</a></td></tr><tr><td>💻 GitHub 저장소</td><td><a href="https://github.com/first-fluke/oh-my-agent" target="_blank" rel="noreferrer">github.com/first-fluke/oh-my-agent</a></td></tr><tr><td>📦 npm 패키지</td><td><a href="https://www.npmjs.com/package/oh-my-agent" target="_blank" rel="noreferrer">npmjs.com/package/oh-my-agent</a></td></tr><tr><td>🚀 풀스택 스타터</td><td><a href="https://github.com/first-fluke/fullstack-starter" target="_blank" rel="noreferrer">github.com/first-fluke/fullstack-starter</a></td></tr></tbody></table><h3 id="추천-워크플로우" tabindex="-1">추천 워크플로우 <a class="header-anchor" href="#추천-워크플로우" aria-label="Permalink to &quot;추천 워크플로우&quot;">​</a></h3><p>오늘 배운 기본 워크플로우 외에 더 강력한 워크플로우들:</p><table tabindex="0"><thead><tr><th>워크플로우</th><th>설명</th></tr></thead><tbody><tr><td><code>/ultrawork</code></td><td>11개 리뷰 게이트가 포함된 5단계 최고 품질 워크플로우</td></tr><tr><td><code>/review</code></td><td>OWASP 보안 + 성능 + 접근성(WCAG) 종합 감사</td></tr><tr><td><code>/coordinate</code></td><td>단계별 멀티 에이전트 수동 조율</td></tr><tr><td><code>/design</code></td><td>7단계 디자인 시스템 구축 워크플로우</td></tr><tr><td><code>/debug</code></td><td>구조화된 근본 원인 진단 및 회귀 테스트</td></tr></tbody></table><h3 id="추천-학습-경로" tabindex="-1">추천 학습 경로 <a class="header-anchor" href="#추천-학습-경로" aria-label="Permalink to &quot;추천 학습 경로&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>오늘: /brainstorm → /plan → /orchestrate (기본)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>다음: /ultrawork (품질 중심 개발)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>심화: /coordinate + oma agent:spawn (수동 오케스트레이션)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>고급: 커스텀 스킬 작성, 워크플로우 설계</span></span></code></pre></div><h2 id="q-a" tabindex="-1">Q&amp;A <a class="header-anchor" href="#q-a" aria-label="Permalink to &quot;Q&amp;A&quot;">​</a></h2><details class="details custom-block"><summary>❓ 자주 묻는 질문</summary><h3 id="oh-my-agent는-무료인가요" tabindex="-1">oh-my-agent는 무료인가요? <a class="header-anchor" href="#oh-my-agent는-무료인가요" aria-label="Permalink to &quot;oh-my-agent는 무료인가요?&quot;">​</a></h3><p>네, MIT 라이선스 오픈소스입니다. 다만 각 AI IDE/CLI의 API 비용은 별도입니다.</p><h3 id="어떤-ai-ide를-써야-하나요" tabindex="-1">어떤 AI IDE를 써야 하나요? <a class="header-anchor" href="#어떤-ai-ide를-써야-하나요" aria-label="Permalink to &quot;어떤 AI IDE를 써야 하나요?&quot;">​</a></h3><p>Antigravity, Claude Code, Cursor, Gemini CLI 모두 지원합니다. 처음이라면 Cursor(GUI)나 Claude Code(CLI)를 추천합니다.</p><h3 id="비개발자도-혼자-쓸-수-있나요" tabindex="-1">비개발자도 혼자 쓸 수 있나요? <a class="header-anchor" href="#비개발자도-혼자-쓸-수-있나요" aria-label="Permalink to &quot;비개발자도 혼자 쓸 수 있나요?&quot;">​</a></h3><p>기본적인 터미널 사용법을 알면 가능합니다. <code>/brainstorm</code>과 <code>/plan</code>은 자연어만으로 진행됩니다.</p><h3 id="한국어로-사용할-수-있나요" tabindex="-1">한국어로 사용할 수 있나요? <a class="header-anchor" href="#한국어로-사용할-수-있나요" aria-label="Permalink to &quot;한국어로 사용할 수 있나요?&quot;">​</a></h3><p>네, <code>user-preferences.yaml</code>에서 <code>language: ko</code>로 설정하면 에이전트들이 한국어로 응답합니다. 11개 언어를 지원합니다.</p><h3 id="기존-프로젝트에도-적용할-수-있나요" tabindex="-1">기존 프로젝트에도 적용할 수 있나요? <a class="header-anchor" href="#기존-프로젝트에도-적용할-수-있나요" aria-label="Permalink to &quot;기존 프로젝트에도 적용할 수 있나요?&quot;">​</a></h3><p>네, <code>bunx oh-my-agent</code>를 기존 프로젝트에서 실행하면 <code>.agents/</code> 폴더만 추가됩니다. 기존 코드에 영향을 주지 않습니다.</p></details><hr><blockquote><p><strong>감사합니다!</strong> 🎉</p><p>더 나은 바이브 코딩 경험을 위해, <a href="https://github.com/first-fluke/oh-my-agent" target="_blank" rel="noreferrer">oh-my-agent에 ⭐ 스타</a>를 눌러주세요.</p></blockquote>`,20)])])}const u=e(l,[["render",d]]);export{p as __pageData,u as default};
